examples:
// Verificando se pode entrar na montanha-russa
let altura: number = 145;

if (altura >= 140) {
  console.log("Pode entrar na montanha-russa!");
}

console.log("Próximo da fila...");

// Aviso de bateria baixa no celular
let bateria: number = 12;

if (bateria < 20) {
  console.log("Bateria baixa! Conecte o carregador.");
}

// Verificando se o aluno pode fazer a prova
let frequencia: number = 80;

if (frequencia >= 75) {
  console.log("Frequência suficiente para fazer a prova");
}

// Checando se tem desconto em uma compra
let totalCompra: number = 250;

if (totalCompra >= 200) {
  console.log("Frete grátis!");
  console.log("Você economizou R$ 15");
}

// Verificando se a temperatura é de febre
let temperatura: number = 38.5;

if (temperatura >= 37.8) {
  console.log("Atenção: possível febre!");
}

// Um if com variável booleana diretamente
let temDeverDeCasa: boolean = true;

if (temDeverDeCasa) {
  console.log("Faça o dever antes de jogar!");
}

// Verificação de senha
let senhaDigitada: string = "abc123";
let senhaCorreta: string = "xyz789";

if (senhaDigitada === senhaCorreta) {
  console.log("Acesso liberado!");
} else {
  console.log("Senha incorreta.");
}

// Par ou ímpar
let numero: number = 17;

if (numero % 2 === 0) {
  console.log("Par");
} else {
  console.log("Ímpar");
}

// Verificação de idade para um filme
let idade: number = 14;
let classificacao: number = 16;

if (idade >= classificacao) {
  console.log("Pode assistir!");
} else {
  console.log("Filme não recomendado para sua idade.");
}

// Preço com ou sem desconto
let temCupom: boolean = true;
let preco: number = 80;

if (temCupom) {
  console.log("Preço com desconto: R$ " + (preco * 0.9));
} else {
  console.log("Preço normal: R$ " + preco);
}

// Verificando conexão com a internet
let conectado: boolean = false;

if (conectado) {
  console.log("Sincronizando dados...");
} else {
  console.log("Sem conexão. Trabalhando offline.");
}

// Checando se um aluno passou de ano
let media: number = 5.5;
const MEDIA_MINIMA: number = 6;

if (media >= MEDIA_MINIMA) {
  console.log("Aprovado! Parabéns!");
} else {
  console.log("Reprovado. Estude mais no próximo semestre.");
}

// Classificação de IMC (Índice de Massa Corporal)
let imc: number = 22;

if (imc < 18.5) {
  console.log("Abaixo do peso");
} else if (imc < 25) {
  console.log("Peso normal");
} else if (imc < 30) {
  console.log("Sobrepeso");
} else {
  console.log("Obesidade");
}

// Faixa etária para ingresso de cinema
let idade: number = 14;

if (idade < 4) {
  console.log("Grátis");
} else if (idade < 12) {
  console.log("Meia-entrada infantil");
} else if (idade < 18) {
  console.log("Meia-entrada");
} else if (idade >= 60) {
  console.log("Meia-entrada idoso");
} else {
  console.log("Inteira");
}

// Saudação baseada na hora do dia
let hora: number = 20;

if (hora < 6) {
  console.log("Boa madrugada!");
} else if (hora < 12) {
  console.log("Bom dia!");
} else if (hora < 18) {
  console.log("Boa tarde!");
} else {
  console.log("Boa noite!");
}

// Nível de bateria com emojis
let bateria: number = 35;

if (bateria > 80) {
  console.log("Bateria cheia");
} else if (bateria > 50) {
  console.log("Bateria ok");
} else if (bateria > 20) {
  console.log("Bateria baixa");
} else {
  console.log("Bateria crítica!");
}

// Classificação de velocidade do vento
let velocidadeVento: number = 45;

if (velocidadeVento >= 90) {
  console.log("Furacão!");
} else if (velocidadeVento >= 60) {
  console.log("Ventania forte");
} else if (velocidadeVento >= 30) {
  console.log("Vento moderado");
} else {
  console.log("Brisa leve");
}

// Faixa de preço de um produto
let preco: number = 75;

if (preco > 500) {
  console.log("Produto premium");
} else if (preco > 100) {
  console.log("Preço médio");
} else if (preco > 30) {
  console.log("Acessível");
} else {
  console.log("Baratinho!");
}

// Comparação de strings (case-sensitive!)
let cidade: string = "Curitiba";

console.log(cidade === "Curitiba"); // true
console.log(cidade === "curitiba"); // false
console.log(cidade !== "São Paulo"); // true

// Usando comparações no if
let idade: number = 16;

if (idade >= 18) {
  console.log("Maior de idade");
}

if (idade < 18) {
  console.log("Menor de idade");
}

// Diferença entre = (atribuir) e === (comparar)
let nota: number = 8;

// nota = 10;     // ATRIBUI: nota agora vale 10
// nota === 10;   // COMPARA: nota é igual a 10? (true/false)

if (nota === 8) {
  console.log("A nota é 8!");
}

// Comparando com variáveis
let precoA: number = 45;
let precoB: number = 60;

console.log(precoA < precoB);  // true
console.log(precoA === precoB); // false
console.log(precoA >= 45);      // true

// >= inclui o valor exato, > não inclui
let pontos: number = 100;

console.log(pontos > 100);  // false (100 não é MAIOR que 100)
console.log(pontos >= 100); // true (100 é MAIOR OU IGUAL a 100)

// && (E): Ambas precisam ser true
let idade: number = 15;
let temAutorizacao: boolean = true;

if (idade >= 14 && temAutorizacao) {
  console.log("Pode participar da excursão!");
}

// || (OU): Basta uma ser true
let temWifi: boolean = false;
let temDadosMoveis: boolean = true;

if (temWifi || temDadosMoveis) {
  console.log("Conectado à internet!");
}

// ! (NÃO): Inverte o valor
let estaChovendo: boolean = false;

if (!estaChovendo) {
  console.log("Pode ir ao parque!");
}

// Combinando vários operadores
let nota: number = 8;
let frequencia: number = 80;
let temTrabalho: boolean = true;

if (nota >= 7 && frequencia >= 75 && temTrabalho) {
  console.log("Aprovado com louvor!");
}

// Regra de desconto: cliente VIP OU compra acima de R$200
let clienteVip: boolean = false;
let totalCompra: number = 250;

if (clienteVip || totalCompra > 200) {
  console.log("Desconto de 10% aplicado!");
}

// Verificação de login
let usuario: string = "admin";
let senha: string = "1234";
let contaBloqueada: boolean = false;

if (usuario === "admin" && senha === "1234" && !contaBloqueada) {
  console.log("Login realizado com sucesso!");
}

// Sistema de classificação de filmes por nota
let avaliacao: number = 7.5;

if (avaliacao >= 9) {
  console.log("Obra-prima");
} else if (avaliacao >= 7) {
  console.log("Muito bom");
} else if (avaliacao >= 5) {
  console.log("Regular");
} else {
  console.log("Ruim");
}

// Classificação de nível de inglês
let pontuacao: number = 72;

if (pontuacao >= 90) {
  console.log("Avançado");
} else if (pontuacao >= 70) {
  console.log("Intermediário");
} else if (pontuacao >= 50) {
  console.log("Básico");
} else {
  console.log("Iniciante");
}

// Faixa de preço de imóvel
let preco: number = 350000;

if (preco >= 1000000) {
  console.log("Luxo");
} else if (preco >= 500000) {
  console.log("Alto padrão");
} else if (preco >= 200000) {
  console.log("Médio padrão");
} else {
  console.log("Popular");
}

// ERRADO: testando de baixo para cima
let nota: number = 95;

// Se fizer assim, 95 cai em >= 60 (que é true!) e vira D
// if (nota >= 60) { console.log("D"); }  // ← nota 95 entraria aqui!

// CERTO: testar de cima para baixo
if (nota >= 90) {
  console.log("A");
} else if (nota >= 80) {
  console.log("B");
}

// Cada else if já "sabe" que as condições anteriores falharam
let nota: number = 85;

// Quando chega aqui, sabemos que nota < 90
// (senão teria entrado no if anterior)
if (nota >= 90) {
  console.log("A");
} else if (nota >= 80) {
  console.log("B"); // 85 cai aqui!
}

// O else final é o "pega-tudo"
let nota: number = 42;

if (nota >= 90) {
  console.log("A");
} else if (nota >= 80) {
  console.log("B");
} else if (nota >= 70) {
  console.log("C");
} else if (nota >= 60) {
  console.log("D");
} else {
  console.log("F"); // Qualquer nota abaixo de 60
}

// Validação antes de processar
let temperatura: number = -300;

if (temperatura < -273 || temperatura > 1000) {
  console.log("Temperatura impossível");
} else if (temperatura < 0) {
  console.log("Abaixo de zero");
} else {
  console.log("Positiva");
}

// Classificação de filme por duração
let duracao: number = 95;

if (duracao <= 0) {
  console.log("Duração inválida");
} else if (duracao < 60) {
  console.log("Curta-metragem");
} else if (duracao < 120) {
  console.log("Longa-metragem");
} else {
  console.log("Longa-metragem estendido");
}

// Por que && não funciona para validação de extremos
let valor: number = -5;

// ERRADO: nenhum número é < 0 E > 1000 ao mesmo tempo!
// if (valor < 0 && valor > 1000) { ... }  // nunca entra!

// CERTO: é < 0 OU é > 1000
if (valor < 0 || valor > 1000) {
  console.log("Valor fora do intervalo");
}

// Classificação de velocidade no trânsito
let velocidade: number = 85;

if (velocidade < 0) {
  console.log("Velocidade inválida");
} else if (velocidade <= 60) {
  console.log("Dentro do limite");
} else if (velocidade <= 80) {
  console.log("Acima do limite");
} else {
  console.log("Muito acima do limite!");
}

// Combinando validação e classificação
let nota: number = 85;

if (nota < 0 || nota > 100) {
  console.log("Nota inválida");
} else if (nota >= 90) {
  console.log("Excelente");
} else if (nota >= 70) {
  console.log("Bom");
} else {
  console.log("Precisa melhorar");
}

// Faixa etária com mais detalhes
let idade: number = 25;

if (idade < 0 || idade > 150) {
  console.log("Idade inválida");
} else if (idade < 2) {
  console.log("Bebê");
} else if (idade < 13) {
  console.log("Criança");
} else if (idade < 18) {
  console.log("Adolescente");
} else {
  console.log("Adulto");
}

// Q1: if (true) sempre executa
if (true) {
  console.log("Isso SEMPRE aparece!");
}

if (false) {
  console.log("Isso NUNCA aparece.");
}

// Q2: && vs || em ação
let a: boolean = true;
let b: boolean = false;

console.log(a && b); // false (precisa das duas)
console.log(a || b); // true (basta uma)

// Q4: apenas UM bloco executa
let x: number = 15;

if (x > 20) {
  console.log("A");
} else if (x > 10) {
  console.log("B"); // ← este roda (15 > 10)
} else {
  console.log("C");
}

// Revisão completa: todos os conceitos juntos
let nota: number = 85;
let frequencia: number = 80;

if (nota >= 90 && frequencia >= 75) {
  console.log("Aprovado com honra");
} else if (nota >= 70 || frequencia >= 90) {
  console.log("Aprovado");
} else {
  console.log("Reprovado");
}

// Técnica: resolver expressões de dentro para fora
// !(10 >= 10 && 3 < 5)
// Passo 1: 10 >= 10 → true
// Passo 2: 3 < 5 → true
// Passo 3: true && true → true
// Passo 4: !true → false
console.log(!(10 >= 10 && 3 < 5)); // false
